    10→// HealthNotifier is a thread-safe mechanism for operators to signal
    11→// that they have completed initialization and are ready to serve.
    12→type HealthNotifier struct {
    13→	ready atomic.Bool
    14→}
    15→
    16→// NewHealthNotifier creates a new HealthNotifier in a not-ready state.
    17→func NewHealthNotifier() *HealthNotifier {
    18→	return &HealthNotifier{}
    19→}
    20→
    21→// SetReady marks the operator as ready. This is safe to call from any goroutine.
    22→func (h *HealthNotifier) SetReady() {
    23→	h.ready.Store(true)
    24→}
    25→
    26→// SetNotReady marks the operator as not ready. This is safe to call from any goroutine.
    27→func (h *HealthNotifier) SetNotReady() {
    28→	h.ready.Store(false)
    29→}
    30→
    31→// IsReady returns true if the operator has signaled readiness.
    32→func (h *HealthNotifier) IsReady() bool {
    33→	return h.ready.Load()
    34→}
    35→
    36→// LivezHandler returns an http.HandlerFunc that always responds 200 OK,
    37→// indicating the process is alive and serving HTTP.
    38→func LivezHandler() http.HandlerFunc {
    39→	return func(w http.ResponseWriter, r *http.Request) {
    40→		w.WriteHeader(http.StatusOK)
    41→		_, _ = w.Write([]byte("OK"))
    42→	}
    43→}
    44→
    45→// ReadyzHandler returns an http.HandlerFunc that responds 200 OK only
    46→// when the HealthNotifier reports ready; otherwise 503 Service Unavailable.
    47→func ReadyzHandler(h *HealthNotifier) http.HandlerFunc {
    48→	return func(w http.ResponseWriter, r *http.Request) {
    49→		if h != nil && h.IsReady() {
    50→			w.WriteHeader(http.StatusOK)
    51→			_, _ = w.Write([]byte("OK"))
    52→			return
    53→		}
    54→		w.WriteHeader(http.StatusServiceUnavailable)
    55→		_, _ = w.Write([]byte("not ready"))
    56→	}
    57→}
    58→
    59→// RegisterHealthEndpoints registers the /livez and /readyz probe endpoints
    60→// on the given router.
    61→func RegisterHealthEndpoints(router *mux.Router, h *HealthNotifier) {
    62→	router.HandleFunc("/livez", LivezHandler()).Methods("GET")
    63→	router.HandleFunc("/readyz", ReadyzHandler(h)).Methods("GET")
    64→}
