    10→// HealthNotifier is a thread-safe mechanism for operators to signal
    11→// that they have completed initialization and are ready to serve.
    12→type HealthNotifier struct {
    13→	ready atomic.Bool
    14→}
    15→
    16→// NewHealthNotifier creates a new HealthNotifier in a not-ready state.
    17→func NewHealthNotifier() *HealthNotifier {
    18→	return &HealthNotifier{}
    19→}
    20→
    21→// SetReady marks the operator as ready. This is safe to call from any goroutine.
    22→func (h *HealthNotifier) SetReady() {
    23→	h.ready.Store(true)
    24→}
    25→
    26→// SetNotReady marks the operator as not ready. This is safe to call from any goroutine.
    27→func (h *HealthNotifier) SetNotReady() {
    28→	h.ready.Store(false)
    29→}
    30→
    31→// IsReady returns true if the operator has signaled readiness.
    32→func (h *HealthNotifier) IsReady() bool {
    33→	return h.ready.Load()
    34→}
