    60→// on the given router.
    61→func RegisterHealthEndpoints(router *mux.Router, h *HealthNotifier) {
    62→	router.HandleFunc("/livez", LivezHandler()).Methods("GET")
    63→	router.HandleFunc("/readyz", ReadyzHandler(h)).Methods("GET")
